class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long num = 1;
        while (true) {
            long long price = 0;
            long long temp = num;
            while (temp > 0) {
                price += __builtin_popcountll(temp);
                temp >>= x;
            }
            if (price * (num + 1) / 2 > k) {
                return num - 1;
            }
            num++;
        }
    }
};
```

